from abc import ABC, abstractmethod

class UserRepository:
    def __init__(self, db: Session):
        self.db = db

    def find_by_id(self, user_id: int) -> User:
        return self.db.query(User).filter(
            User.id == user_id
        ).first()

    def save(self, user: User) -> User:
        self.db.add(user)
        self.db.commit()
        return user

